class Solution:
    def minChanges(self, s):
        n = len(s)
        INF = float('inf')
        dp = [INF] * (n + 1)
        dp[0] = 0
        for i in range(0, n, 2):
            if dp[i] == INF:
                continue
            zeros = 0
            ones = 0
            for length in range(2, n - i + 1, 2):
                for pos in (i + length - 2, i + length - 1):
                    if s[pos] == '0':
                        zeros += 1
                    else:
                        ones += 1
                cost = min(zeros, ones)
                if dp[i] + cost < dp[i + length]:
                    dp[i + length] = dp[i] + cost
        return dp[n]

